INSERT INTO "legal_documents" ("slug", "title", "content_html") VALUES
('about', 'О нас', '<h1>О нас</h1><p>Мы команда школы развития женственности и осознанности под руководством Жанны Слямовой. Помогаем женщинам выстраивать здоровые отношения с собой, телом и партнёром через авторские курсы, индивидуальную работу и сообщество.</p><h2>Что у нас можно получить</h2><ul><li>Онлайн-курсы и образовательные программы</li><li>Индивидуальные коуч-сессии</li><li>Доступ к закрытым Telegram-каналам</li><li>Сопутствующие продукты и материалы</li></ul><h2>Связаться с нами</h2><p>По вопросам поддержки и сотрудничества — через раздел «Обратная связь» в приложении.</p>'),
('privacy', 'Политика конфиденциальности', '<h1>Политика конфиденциальности</h1><p>Настоящая Политика описывает, какие персональные данные обрабатывает приложение «Жанна Слямова» (далее — «Сервис») и как мы их защищаем.</p><h2>1. Какие данные мы собираем</h2><ul><li>Имя и фамилия</li><li>Адрес электронной почты, номер телефона</li><li>Фотография профиля (по вашему выбору)</li><li>Дата рождения (если указана)</li><li>История заказов, отзывы, переписка с менеджером</li><li>Технические данные: платформа устройства, версия приложения</li></ul><h2>2. Зачем</h2><ul><li>Оказание услуг и доставка приобретённых товаров</li><li>Авторизация и безопасность аккаунта</li><li>Связь по заказам, обратной связи и поддержке</li><li>Отправка уведомлений в приложении</li><li>Улучшение работы сервиса</li></ul><h2>3. Как мы храним данные</h2><p>Данные хранятся на защищённых серверах. Доступ имеют только сотрудники, которым он необходим для выполнения работы. Мы не продаём ваши данные третьим лицам.</p><h2>4. Сторонние сервисы</h2><p>Часть данных может передаваться доверенным сервисам, обеспечивающим работу приложения: сервису аутентификации (Firebase), почтовому сервису, платёжному провайдеру в момент оплаты. Каждый из них соблюдает собственные политики защиты данных.</p><h2>5. Ваши права</h2><ul><li>Запросить копию своих данных</li><li>Запросить исправление или удаление данных</li><li>Отозвать согласие на обработку</li></ul><h2>6. Контакты</h2><p>По вопросам обработки данных — через раздел «Обратная связь» в приложении.</p><h2>7. Изменения политики</h2><p>Мы можем обновлять настоящую Политику. Актуальная версия всегда доступна в приложении.</p>'),
('terms', 'Условия использования', '<h1>Условия использования</h1><p>Настоящие Условия регулируют использование мобильного и веб-приложения «Жанна Слямова» (далее — «Сервис»). Используя Сервис, вы подтверждаете согласие с этими Условиями.</p><h2>1. Регистрация и аккаунт</h2><p>Для использования Сервиса требуется регистрация. Вы обязуетесь предоставлять достоверные данные и поддерживать их актуальность. Один пользователь — один аккаунт. Передача аккаунта третьим лицам не допускается.</p><h2>2. Контент</h2><p>Все материалы курсов, статей, видео и иных образовательных продуктов, размещённых в Сервисе, принадлежат правообладателю. Их запрещается копировать, распространять, перепродавать или публично размещать без письменного разрешения.</p><h2>3. Поведение пользователей</h2><p>В Сервисе запрещено:</p><ul><li>Публиковать оскорбительные, противоправные или вводящие в заблуждение сообщения</li><li>Использовать Сервис для рассылки спама или мошенничества</li><li>Совершать действия, направленные на нарушение работы Сервиса</li><li>Создавать несколько аккаунтов для обхода ограничений</li></ul><h2>4. Ограничение доступа</h2><p>Мы можем ограничить или закрыть доступ к Сервису при нарушении настоящих Условий. Возврат оплаченных, но не использованных услуг производится в порядке, предусмотренном Публичной офертой.</p><h2>5. Ответственность</h2><p>Сервис предоставляется «как есть». Мы прилагаем разумные усилия для бесперебойной работы, но не гарантируем абсолютной доступности. Ответственность за решения и действия, предпринятые на основе материалов Сервиса, лежит на пользователе.</p><h2>6. Изменения условий</h2><p>Мы можем обновлять настоящие Условия. При существенных изменениях — уведомление в приложении. Продолжение использования Сервиса после изменений означает согласие с новой редакцией.</p><h2>7. Применимое право</h2><p>Настоящие Условия регулируются законодательством Республики Казахстан.</p>'),
('offer', 'Публичная оферта', '<h1>Публичная оферта</h1><p>Настоящий документ является публичной офертой о заключении договора купли-продажи и оказания услуг через мобильное и веб-приложение «Жанна Слямова». Совершая оплату, вы (далее — «Покупатель») заключаете договор на условиях, описанных ниже.</p><h2>1. Предмет договора</h2><p>Продавец предоставляет Покупателю следующие виды товаров и услуг:</p><ul><li>Доступ к онлайн-курсам и образовательным программам</li><li>Индивидуальные консультации и коуч-сессии</li><li>Доступ к закрытым Telegram-каналам</li><li>Цифровые и физические товары</li></ul><h2>2. Порядок оформления заказа</h2><p>Покупатель выбирает товар или услугу в Сервисе и оформляет заказ. После оплаты заказ считается принятым.</p><h2>3. Стоимость и оплата</h2><p>Стоимость указана в Сервисе в тенге. Оплата производится способами, предложенными в момент оформления заказа. Цена действительна на момент оплаты.</p><h2>4. Доступ к цифровым продуктам</h2><p>Доступ к курсам, материалам и закрытым каналам предоставляется обычно мгновенно после подтверждения оплаты. Срок действия доступа указывается в описании конкретного товара.</p><h2>5. Оказание услуг</h2><p>Дата и время коуч-сессий и иных индивидуальных услуг согласовываются через приложение. Перенос возможен по согласованию сторон не позднее чем за 24 часа до начала.</p><h2>6. Возвраты</h2><p>Возврат денежных средств возможен в следующих случаях:</p><ul><li>Цифровые товары и доступ к курсам — до момента первого использования (открытия первого урока, входа в закрытый канал)</li><li>Индивидуальные услуги — при отмене не позднее чем за 24 часа до начала</li><li>Физические товары — в течение 14 дней с момента получения, при сохранении товарного вида и упаковки</li></ul><p>Возврат осуществляется тем же способом, которым была произведена оплата, в течение 10 рабочих дней после получения запроса.</p><h2>7. Ответственность сторон</h2><p>Продавец отвечает за качество и описание предоставляемых товаров и услуг. Покупатель отвечает за достоверность данных, указанных при оформлении заказа, и за соблюдение Условий использования.</p><h2>8. Защита персональных данных</h2><p>Обработка персональных данных Покупателя регулируется Политикой конфиденциальности.</p><h2>9. Применимое право и споры</h2><p>Настоящая Оферта регулируется законодательством Республики Казахстан. Споры решаются путём переговоров; при невозможности — в судебном порядке по месту нахождения Продавца.</p><h2>10. Срок действия и изменения</h2><p>Оферта действует с момента публикации в Сервисе. Продавец оставляет за собой право вносить изменения. Заказы, оформленные до изменения, исполняются по условиям, действовавшим на момент оплаты.</p>')
ON CONFLICT ("slug") DO NOTHING;